public class WebURL { protected URI theURL ; protected String rawQueryPart ; public WebURL ( String url ) throws URISyntaxException { theURL = new URI ( url ) ; rawQueryPart = null ; } public WebURL ( String scheme , String host , int port , String path , String queryPart ) throws URISyntaxException { theURL = new URI ( scheme , null , host , port , path , null , null ) ; rawQueryPart = queryPart ; } public WebURL ( URI theURL ) { this ( theURL , null ) ; } public WebURL ( URI theURL , String rawQueryPart ) { this . theURL = theURL ; this . rawQueryPart = rawQueryPart ; } public WebURL resolve ( String raw ) throws URISyntaxException { URI rawURL = new URI ( raw ) ; if ( rawURL . isAbsolute ( ) ) return new WebURL ( rawURL ) ; URI fixedURL = theURL ; if ( theURL . getPath ( ) == null || theURL . getPath ( ) . length ( ) == 0 ) fixedURL = new URI ( theURL . getScheme ( ) , null , theURL . getHost ( ) , theURL . getPort ( ) , "/" , null , null ) ; if ( raw . startsWith ( "?" ) ) return new WebURL ( fixedURL . getScheme ( ) , fixedURL . getHost ( ) , fixedURL . getPort ( ) , fixedURL . getPath ( ) , rawURL . getRawQuery ( ) ) ; return new WebURL ( fixedURL . resolve ( rawURL ) ) ; } public String getPath ( ) { return theURL . getPath ( ) ; } public String getHost ( ) { return theURL . getHost ( ) ; } public String getScheme ( ) { return theURL . getScheme ( ) ; } public int getPort ( ) { return theURL . getPort ( ) ; } public String getRawQuery ( ) { if ( rawQueryPart != null ) return rawQueryPart ; return theURL . getRawQuery ( ) ; } public String toASCIIString ( ) { String rval = theURL . toASCIIString ( ) ; if ( rval != null && rawQueryPart != null && rawQueryPart . length ( ) > 0 ) rval += "?" + rawQueryPart ; return rval ; } public String toString ( ) { String rval = theURL . toString ( ) ; if ( rval != null && rawQueryPart != null && rawQueryPart . length ( ) > 0 ) rval += "?" + rawQueryPart ; return rval ; } }